--
-- Estructura de tabla para la tabla `summaries`
--

CREATE TABLE `summaries` (
  `id` int(11) NOT NULL,
  `work_id` int(11) NOT NULL,
  `chapter` int(11) DEFAULT NULL,
  `tipo` varchar(50) DEFAULT NULL,
  `contenido` text NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Volcado de datos para la tabla `summaries`
--

INSERT INTO `summaries` (`id`, `work_id`, `chapter`, `tipo`, `contenido`) VALUES
(1, 1, 1, 'Capítulo', '<p class=\"pjustificado\">La historia comienza en una tarde gris de noviembre. Jane Eyre, una huérfana de 10 años, intenta pasar desapercibida leyendo La historia de los \r\n                pájaros británicos de Bewick tras una cortina. Su tía, la Sra. Reed, la excluye del círculo familiar, mientras su primo John Reed la acosa físicamente y verbalmente, \r\n                recordándole que vive allí solo por caridad.</p>\r\n            <p class=\"pjustificado\">Tras recibir un golpe con un libro lanzado por John, Jane finalmente explota y se defiende, tachándolo de \"asesino\" y \"esclavo\". La Sra. Reed interviene de inmediato, \r\n                culpando exclusivamente a Jane y ordenando su castigo más temido: el encierro en el \"Cuarto Rojo\", el lugar donde murió su tío Reed.</p> '),
(2, 1, 2, 'Capítulo', '<p class=\"pjustificado\">Jane es arrastrada por las criadas Abbott y Bessie al temido Cuarto Rojo. Al verse reflejada en el espejo, se siente como un espíritu extraño y comienza a meditar sobre\r\n                su injusta situación: recuerda que su tío Reed la acogió tras la muerte de sus padres y que, en su lecho de muerte, hizo jurar a su esposa que la criaría como a una hija,\r\n                promesa que la tía ha roto sistemáticamente.</p>\r\n            <p class=\"pjustificado\">El aislamiento y la oscuridad alimentan su imaginación hasta que cree ver la aparición del fantasma de su tío, quien vendría a vengarla. Aterrorizada, Jane suplica que la \r\n                dejen salir, pero la Sra. Reed ignora sus gritos tachándolos de artimaña dramática. Finalmente, el pánico y el agotamiento hacen que Jane se desmaye.</p>'),
(3, 1, 3, 'Capítulo', '<p class=\"pjustificado\">Jane despierta en su habitación bajo el cuidado del amable boticario, el Sr. Lloyd, y de Bessie, quien muestra cierta compasión por el trato recibido por la niña. \r\n                Tras el trauma, el Sr. Lloyd conversa con Jane y, al notar su infelicidad, sugiere a la Sra. Reed que la envíen a una escuela, idea que despierta en Jane una cautelosa esperanza.</p>\r\n            <p class=\"pjustificado\">Mientras se recupera, Jane escucha una charla entre las criadas donde descubre su origen: su madre, de la familia Reed, fue desheredada por casarse con un clérigo pobre. \r\n                Ambos murieron de tifus cuando Jane era un bebé, dejando a la niña en manos de una familia que nunca la quiso.</p>'),
(4, 1, 4, 'Capítulo', '<p class=\"pjustificado\">Tras dos meses de espera y mayor aislamiento, Jane conoce al Sr. Brocklehurst, el severo director de la escuela Lowood. Durante un interrogatorio humillante sobre religión, \r\n                Jane admite con honestidad que los salmos no le interesan, lo que indigna al clérigo. Para colmo, la Sra. Reed la calumnia ante él tildándola de mentirosa, asegurando que esa \r\n                será su carta de presentación en el colegio.</p>\r\n            <p class=\"pjustificado\">Una vez que Brocklehurst se marcha, Jane, herida profundamente, explota contra su tía en una famosa declaración de independencia: le comunica que no es su pariente, \r\n                que nunca la volverá a llamar \"tía\" y que su recuerdo le produce asco. Ante esta furia, la Sra. Reed se queda sin palabras, derrotada por primera vez. \r\n                Antes de partir hacia su nueva vida, Jane recibe un inusual gesto de cariño de Bessie, quien le confiesa que la prefiere a ella antes que a los niños Reed.</p>'),
(5, 1, 5, 'Capítulo', '<p class=\"pjustificado\">Jane emprende sola un largo viaje en carruaje hasta llegar a Lowood en un día gris y lluvioso. La atmósfera del edificio \r\n                es sombría y austera, marcando un fuerte contraste con el lujo de Gateshead. Al día siguiente, Jane descubre la rígida disciplina del internado: \r\n                una rutina agotadora que comienza antes del amanecer, marcada por el frío, el hambre y las oraciones constantes.</p>\r\n            <p class=\"pjustificado\">En este entorno conoce a dos figuras opuestas: la amable superintendente Miss Temple y la severa Miss Scatcherd, quien castiga\r\n                injustamente a una alumna llamada Helen Burns. Jane entabla amistad con Helen y descubre la cruda realidad de la institución: Lowood es una escuela\r\n                de caridad para huérfanas financiada por donaciones, lo que confirma que la tía Reed no ha gastado un céntimo en su educación. Además, comprende que\r\n                el Señor Brocklehurst ejerce un control tiránico sobre cada detalle del lugar.</p>'),
(6, 1, 6, 'Capítulo', '<p class=\"pjustificado\">La vida en Lowood se revela en toda su dureza: las niñas despiertan con el agua de las palanganas congelada y sufren hambre constante\r\n                y sermones interminables. En este ambiente de privación, Jane observa con asombro a Helen Burns, quien soporta con una paciencia sobrehumana los castigos\r\n                y humillaciones de la Srta. Scatcherd.</p>\r\n            <p class=\"pjustificado\">Helen le explica a Jane su filosofía de resignación cristiana: cree en devolver bien por mal y en aceptar el sufrimiento con humildad.\r\n                Jane, fiel a su sentido de la justicia, rechaza frontalmente esta idea de sumisión ante la tiranía. Mientras Jane admira la vasta cultura de su amiga, \r\n                Helen se critica a sí misma por ser \"distraída\" y soñar con su hogar, demostrando un nivel de autodisciplina que Jane aún no logra comprender.</p>'),
(7, 1, 7, 'Capítulo', '<p class=\"pjustificado\">Tras un mes de ausencia, el Señor Brocklehurst regresa a Lowood, aumentando la ansiedad de Jane. Durante su inspección, \r\n                Jane deja caer accidentalmente su pizarra, lo que el director aprovecha para descargar su furia. Cumpliendo la promesa que le hizo a la Sra. Reed, \r\n                obliga a Jane a subirse a un taburete y la denuncia ante toda la escuela como una mentirosa, prohibiendo a las demás alumnas hablar con ella durante el resto del día.</p>\r\n            <p class=\"pjustificado\">A pesar de la vergüenza extrema, Jane encuentra consuelo en Helen Burns. Mientras las demás la ignoran, Helen le dedica sonrisas \r\n                cómplices y silenciosas cada vez que pasa a su lado, demostrando una lealtad que ayuda a Jane a soportar la humillación pública.</p>'),
(8, 1, 8, 'Capítulo', '<p class=\"pjustificado\">Tras la humillación, Jane se derrumba creyendo que su reputación está destruida para siempre, pero Helen la consuela asegurándole que sus compañeras\r\n                s sienten lástima por ella, no desprecio. Poco después, Miss Temple invita a ambas a su habitación y permite que Jane cuente su verdadera historia sobre Gateshead y la tía Reed.</p>\r\n            <p class=\"pjustificado\">Miss Temple, mostrando una confianza ciega en Jane, escribe al Sr. Lloyd para confirmar los hechos. Mientras esperan la respuesta, \r\n                comparte con las niñas un té con pastel, un gesto de humanidad inolvidable para Jane. Cuando llega la carta del boticario corroborando la versin de la nia, \r\n                Miss Temple limpia el nombre de Jane ante toda la escuela. Liberada de la etiqueta de \"mentirosa\", Jane se entrega con pasin a sus estudios, destacando pronto en dibujo y francs.</p>'),
(9, 1, 9, 'Capítulo', '<p class=\"pjustificado\">Con la llegada de la primavera, la ubicación insalubre de Lowood provoca un brote masivo de tifus que afecta a más de la mitad de las niñas. \r\n                Mientras Jane se mantiene sana y disfruta de una libertad inusual jugando al aire libre, descubre con horror que Helen Burns está agonizando, pero no de tifus, \r\n                sino de tuberculosis (consunción).</p>\r\n            <p class=\"pjustificado\">Una noche, Jane se cuela en la habitación de Miss Temple para ver a su amiga por última vez. En una escena desgarradora, Helen la consuela \r\n                diciéndole que no teme a la muerte y que está en paz por abandonar el sufrimiento del mundo. Ambas se quedan dormidas abrazadas en la misma cama; a la mañana siguiente,\r\n                Helen ha muerto. Quince años después, se coloca sobre su tumba una placa con la palabra <i>Resurgam</i> (\"Resurgir\"), simbolizando la fe de Helen y el impacto eterno que dejó en Jane.</p>'),
(10, 1, 10, 'Capítulo', '<p class=\"pjustificado\">Tras el escándalo del tifus, una nueva directiva asume el control de Lowood, mejorando drásticamente las condiciones de vida. Jane pasa allí ocho años: \r\n                seis como alumna brillante y dos como maestra. Sin embargo, tras el matrimonio y la partida de su mentora, Miss Temple, Jane siente que su mundo se ha quedado pequeño y \r\n                decide buscar nuevos horizontes, aceptando un puesto de institutriz en una mansión llamada Thornfield.</p>\r\n            <p class=\"pjustificado\">Antes de partir, recibe la visita de Bessie, quien le pone al día sobre los Reed: sus primas están enfrentadas tras un intento de fuga amorosa de Georgiana,\r\n                y su primo John se ha hundido en la depravación. Lo más impactante es la noticia de que un tío paterno, John Eyre, la buscó hace siete años antes de partir hacia Madeira en \r\n                busca de fortuna. Con esta mezcla de pasado y futuro, Jane se despide de Bessie y se encamina, llena de determinació n, hacia su nueva vida.</p>'),
(11, 1, 11, 'Capítulo', '<p class=\"pjustificado\">Jane llega a Thornfield Hall de noche, encontrando un interior acogedor que contrasta con la oscuridad exterior. Allí la recibe la Sra. Fairfax, \r\n                una anciana amable que Jane confunde con la dueña, aunque pronto aclara que es solo la ama de llaves. El verdadero dueño es el Sr. Rochester, un hombre excéntrico y viajero \r\n                que rara vez está en casa. Jane conoce su misión: ser la institutriz de Adèle, una niña francesa de ocho años protegida de Rochester.</p>\r\n            <p class=\"pjustificado\">Sin embargo, la calma se rompe cuando Jane escucha una risa tétrica y antinatural que resuena por los pasillos. La Sra. Fairfax resta importancia al incidente \r\n                culpando a Grace Poole, una costurera de carácter difícil y errático que trabaja en la casa. Aunque Jane acepta la explicación, la inquietud queda sembrada en el ambiente.</p>'),
(12, 1, 12, 'Capítulo', '<p class=\"pjustificado\">La vida en Thornfield resulta agradable para Jane; Adèle es una alumna vivaz aunque algo consentida, y Jane disfruta de la paz de la mansión, \r\n                aunque a veces siente una inquietud errante que la lleva a recorrer los pasillos del piso superior. Una tarde de invierno, mientras pasea sola bajo la luna, escucha \r\n                la llegada de un caballo y un perro, lo que le recuerda a los \"Gytrash\" (espíritus en forma de animales) de los cuentos de Bessie.</p>\r\n            <p class=\"pjustificado\">El hechizo se rompe cuando el caballo resbala en el hielo y su jinete cae al suelo. Jane, lejos de asustarse, ayuda al hombre a levantarse. \r\n                Nota que es un hombre de unos 35 años, de rasgos severos, tez oscura y ceño fruncido. Al regresar a la casa, Jane descubre al perro (Pilot) en la alfombra y se entera \r\n                por los criados de que el hombre al que ayudó no es otro que el Sr. Rochester, quien acaba de regresar a su hogar con un tobillo torcido tras el accidente.</p>'),
(13, 1, 13, 'Capítulo', '<p class=\"pjustificado\">Al día siguiente de su accidentado encuentro, Rochester invita a Jane y a Adèle a tomar el té. Su comportamiento es brusco, frío y errático, rompiendo\r\n                con todas las etiquetas sociales esperadas de un anfitrión. Sin embargo, se queda fascinado al examinar los dibujos de Jane, reconociendo en ellos una mente profunda y \r\n                original que no encaja con la de una simple institutriz.</p>\r\n            <p class=\"pjustificado\">Tras el encuentro, Jane confiesa a la Sra. Fairfax que encuentra a su amo \"cambiante y abrupto\". El ama de llaves justifica su carácter explicando su\r\n                complicado pasado familiar: Rochester era el \"paria\" de la familia, mientras que su hermano mayor heredó todo. Solo tras la muerte de su padre y de su hermano, hace nueve \r\n                años, Edward se convirtió en el dueño de Thornfield, una posición que parece ocupar más por deber que por gusto.</p>'),
(14, 1, 14, 'Capítulo', '<p class=\"pjustificado\">Una noche, en un estado de ánimo más relajado (y algo ebrio), Rochester manda llamar a Jane y a Adèle. Mientras la niña se entretiene con sus regalos, \r\n                Rochester se muestra inusualmente parlanchín y desafiante. En un momento de sinceridad brutal, le pregunta a Jane si lo encuentra guapo; ella, sin pensarlo, responde con un \r\n                rotundo \"no\", lo que divierte al amo de la casa por su falta de hipocresía.</p>\r\n            <p class=\"pjustificado\">La conversación se vuelve profunda y extraña: Rochester insiste en que no la ve como una sirvienta y discuten sobre temas densos como el pecado, \r\n                el remordimiento y la redención. Él insinúa que ha cometido errores en el pasado y que busca un camino para ser \"limpio\" de nuevo. El capítulo termina con una mención \r\n                a la madre de Adèle, dejando a Jane con la intriga de un secreto que Rochester promete revelarle pronto.</p>'),
(15, 1, 15, 'Capítulo', '<p class=\"pjustificado\">Rochester cumple su promesa y revela a Jane su pasado: tuvo un romance con una bailarina francesa, Céline Varens, quien le fue infiel con otro hombre.\r\n                Aunque Rochester duda que Adèle sea su hija biológica (ya que no se le parece en nada), decidió traerla a Inglaterra para que no quedara abandonada cuando su madre la dejó. \r\n                Esta confesión humaniza a Rochester ante los ojos de Jane.</p>\r\n            <p class=\"pjustificado\">Esa misma noche, el misterio gótico estalla: Jane oye pasos en el pasillo y una risa demoníaca. Al salir, descubre que la habitación de Rochester está en llamas. \r\n                Jane actúa con rapidez y le salva la vida arrojando agua sobre su cama. Tras el incidente, Rochester sube misteriosamente al tercer piso y, al volver, confirma la sospecha de Jane\r\n                de que la culpable es Grace Poole, pero le ordena guardar silencio absoluto sobre lo ocurrido. El capítulo termina con una nota de intensa gratitud y una conexión emocional que\r\n                deja a Jane incapaz de dormir.</p>'),
(16, 1, 16, 'Capítulo', '<p class=\"pjustificado\">Al día siguiente, Jane se asombra al ver que el intento de asesinato no ha causado ningún escándalo; los criados creen que fue un accidente con una\r\n                vela y la propia Grace Poole cose tranquilamente como si nada hubiera pasado. Jane no entiende por qué Rochester protege a una criminal, pero sus pensamientos pronto se\r\n                desvían hacia sus propios sentimientos: se da cuenta de que está enamorándose de su amo.</p>\r\n            <p class=\"pjustificado\">La decepción llega cuando se entera de que Rochester se ha marchado por varios días para asistir a una fiesta donde estará la bella Blanche Ingram. \r\n                Para \"curarse\" de sus ilusiones, Jane se impone un castigo psicológico: dibuja un autorretrato tosco de sí misma y un retrato idealizado de la hermosa Blanche.\r\n                Al compararlos, se obliga a recordar su posición como una \"pobre institutriz plana\" para no hacerse falsas esperanzas con un hombre de la clase de Rochester.</p>'),
(17, 1, 17, 'Capítulo', '<p class=\"pjustificado\">Tras una semana de angustia pensando que Rochester se irá a Europa por un año, la Sra. Fairfax recibe noticias de que él regresará con una gran comitiva de invitados. \r\n                Mientras preparan la casa, Jane sigue desconcertada por Grace Poole: escucha a los criados murmurar sobre el sueldo inusualmente alto que recibe la costurera, lo que confirma sus sospechas\r\n                de que Grace guarda un secreto que le da poder sobre Rochester.</p>\r\n            <p class=\"pjustificado\">Finalmente, llega la caravana de nobles, incluida la altiva Blanche Ingram. Jane es obligada a bajar al salón, pero se refugia en el hueco de una ventana, observando\r\n                desde las sombras. Blanche y su madre no ocultan su desprecio por las institutrices, tratándola como un objeto insignificante. Cuando Jane intenta escapar de la reunión\r\n                abrumada por la humillación, Rochester la intercepta. Al ver que ella está a punto de llorar, la deja ir, pero no sin antes casi traicionarse con un \"Buenas noches, mi...\", \r\n                cortando la frase justo a tiempo.</p>'),
(18, 1, 18, 'Capítulo', '<p class=\"pjustificado\">La estancia de los invitados continúa y Jane observa con dolor cómo Rochester y Blanche Ingram actúan como la pareja perfecta, compitiendo juntos en juegos de mímica\r\n                (charades). Jane llega a la amarga conclusión de que se casarán pronto, aunque nota que no hay amor: Blanche busca la fortuna de él, y él busca la belleza y el estatus de ella.</p>\r\n            <p class=\"pjustificado\">En medio de estas fiestas, llega un invitado inesperado: el Sr. Mason, un hombre que a Jane le produce una instintiva repulsión por su mirada vacía. De él descubre\r\n                un dato nuevo: Rochester vivió un tiempo en las Indias Occidentales (el Caribe). La noche se vuelve aún más extraña con la llegada de una vieja gitana que se ofrece a leer la fortuna\r\n                de los invitados. Blanche entra primero, pero sale de la consulta visiblemente decepcionada y de mal humor, lo que sugiere que la gitana le ha dicho algo que no quería oír sobre su \r\n                futuro con Rochester.</p>'),
(19, 1, 19, 'Capítulo', '<p class=\"pjustificado\">Jane entra en la biblioteca con escepticismo, pero pronto queda fascinada por las palabras de la supuesta gitana. La anciana demuestra conocer los sentimientos\r\n                más íntimos de Jane y le asegura que está muy cerca de alcanzar la felicidad. Además, le confiesa el truco que usó con Blanche Ingram: le dijo que la fortuna de Rochester no era tan\r\n                grande como ella pensaba, lo que explica el mal humor de la aristócrata (quien solo busca el dinero).</p>\r\n            <p class=\"pjustificado\">A medida que la \"anciana\" habla, su voz se vuelve más profunda y familiar. Jane descubre con asombro que la gitana es, en realidad, el propio Rochester disfrazado. \r\n                Aunque Jane lo reprende por el engaño, la atmósfera juguetona desaparece cuando ella le menciona la llegada del Sr. Mason. Al oír el nombre, Rochester se transmuta: se pone pálido y \r\n                se apoya en Jane, visiblemente perturbado por la presencia de este hombre de su pasado.</p>'),
(20, 1, 20, 'Capítulo', '<p class=\"pjustificado\">La paz de la noche se rompe con un grito desgarrador. Rochester calma a los invitados diciendo que ha sido la pesadilla de un criado, pero poco después busca\r\n                a Jane en secreto. Tras preguntarle si teme a la sangre, la lleva al tercer piso, donde encuentran al Sr. Mason apuñalado y mordido en el brazo. Rochester deja a Jane sola cuidando\r\n                al herido con la orden estricta de que no hablen entre ellos. En ese silencio tenso, Jane observa un tapiz de la crucifixión, sintiendo la pesadez del misterio que rodea a Grace Poole.</p>\r\n            <p class=\"pjustificado\">Tras ayudar a Mason a marchar de la casa en secreto antes del amanecer, Rochester lleva a Jane al huerto. Allí, le cuenta una historia \"hipotética\": un joven \r\n                comete un \"error capital\" en un país extranjero y, tras años de disipación, intenta redimirse con una mujer pura, pero las convenciones sociales se lo impiden. Le pregunta a Jane \r\n                si ese hombre tendría derecho a \"saltarse los obstáculos de la costumbre\". Jane, firme en su moral, le responde que debe buscar la redención en Dios, no en otra persona. \r\n                Rochester termina la charla sugiriendo que casarse con Blanche es su única salida, dejándola sumida en la confusión.</p>'),
(21, 1, 21, 'Capítulo', '<p class=\"pjustificado\">Tras una serie de sueños premonitorios con bebés (mal augurio en el folclore inglés), Jane recibe noticias devastadoras: su primo John Reed se ha suicidado\r\n                tras una vida de excesos, y su tía, la Sra. Reed, ha sufrido un derrame cerebral. Jane regresa a su antiguo hogar, donde se reencuentra con una Bessie fiel y con sus primas: \r\n                Eliza, ahora fría y volcada en la religión, y Georgiana, tan bella como superficial. Ambas hermanas se detestan profundamente.</p>\r\n            <p class=\"pjustificado\">A pesar del odio que recibió de niña, Jane intenta reconciliarse con su tía moribunda. En un último acto de confesión, la Sra. Reed le entrega una carta de \r\n                hace tres años de su tío, John Eyre, quien quería adoptarla y dejarle su fortuna. La tía confiesa que, por puro rencor, ocultó la carta para evitar que Jane prosperara. \r\n                Aun sabiendo esto, Jane le ofrece su perdón, pero la Sra. Reed muere a medianoche manteniendo su hostilidad hasta el último aliento, incapaz de aceptar la bondad de la sobrina\r\n                que tanto maltrató.</p>'),
(22, 1, 22, 'Capítulo', '<p class=\"pjustificado\">Jane prolonga su estancia en Gateshead un mes más para ayudar a sus primas a organizar sus vidas tras la muerte de su tía: Georgiana se marcha a Londres y Eliza\r\n                ingresa en un convento en Francia (donde acabará siendo Madre Superiora). Antes de irse, Jane recibe noticias de la Sra. Fairfax: los invitados se han ido y Rochester ha viajado \r\n                a Londres para comprar un nuevo carruaje, lo que todos interpretan como el paso definitivo para su boda con Blanche Ingram.</p>\r\n            <p class=\"pjustificado\">El reencuentro se produce de forma inesperada en el camino hacia la mansión. Al ver a Rochester, Jane no puede ocultar su alegría. Él la provoca hablando del \r\n                nuevo carruaje y de lo bien que le sentará a la futura \"Sra. Rochester\", manteniendo la farsa de su compromiso. En un arrebato de sinceridad que nace del alivio de volver a verlo,\r\n                Jane pronuncia una de las frases más famosas del libro: \"Dondequiera que usted esté, es mi hogar; mi único hogar\". Al llegar a Thornfield, el cálido recibimiento de los criados y\r\n                de Adèle refuerza esa sensación de pertenencia que Jane nunca antes había sentido.</p>'),
(23, 1, 23, 'Capítulo', '<p class=\"pjustificado\">Tras dos semanas de tensa calma, Rochester encuentra a Jane en el jardín y la invita a pasear. Con crueldad aparente, le confirma que se casará con Blanche y\r\n                que ha encontrado para ella un puesto de institutriz en Irlanda. La idea de cruzar el mar y alejarse de él rompe la compostura de Jane. Sentados bajo un gran castaño, Rochester\r\n                habla de un \"vínculo de comunicación\" que los une, como si un hilo invisible conectara sus corazones.</p>\r\n            <p class=\"pjustificado\">Jane, incapaz de contenerse más, explota en un llanto amargo y le confiesa que lo ama, gritando que no es una \"máquina sin sentimientos\" y que sus almas son \r\n                iguales. Para su absoluta sorpresa, Rochester le pide que sea su esposa. Tras una inicial desconfianza (él admite que usó a Blanche solo para despertar sus celos), Jane acepta emocionada.\r\n                Sin embargo, la naturaleza parece protestar: una tormenta estalla de inmediato y, esa misma noche, un rayo parte en dos el castaño donde minutos antes se habían jurado amor, \r\n                un símbolo clarísimo de que su unión está marcada por la tragedia.</p>'),
(24, 1, 24, 'capítulo', '<p class=\"pjustificado\">Los preparativos de la boda comienzan, pero no traen la paz que Jane esperaba. La Sra. Fairfax se muestra fría y desaprobadora; incluso tras saber que hay\r\n                un compromiso formal, advierte a Jane que sea cautelosa, sugiriendo que la diferencia de edad y clase social es un peligro. Jane misma se siente inquieta, casi asustada,\r\n                cuando Rochester la llama \"Jane Rochester\", como si ese nombre borrara su verdadera identidad.</p>\r\n            <p class=\"pjustificado\">Rochester intenta colmarla de joyas, vestidos caros y lujos, tratando de convertirla en una figura de cuento de hadas. Sin embargo, Jane reacciona con pánico\r\n                y autoprotección: ella no quiere ser una \"esclava\" comprada con seda, sino seguir siendo ella misma. Siente el presentimiento de que esta felicidad es demasiado irreal para durar.\r\n                Para ganar algo de independencia económica y sentirse más igual a su prometido, decide escribir a su tío John Eyre en Madeira, con la esperanza de que una futura herencia la ponga \r\n                en una posición de mayor dignidad frente a la fortuna de Rochester.</p>\r\n'),
(25, 1, 25, 'Capítulo', '<p class=\"pjustificado\">La víspera de la boda, Jane espera a Rochester con una ansiedad creciente. Cuando él llega, ella le confiesa una experiencia aterradora que ocurrió la noche anterior: \r\n                mientras dormía, una mujer de aspecto \"salvaje\" y facciones gruesas entró en su habitación, se probó el velo de novia de Jane ante el espejo y, acto seguido, lo rasgó en dos antes de pisotearlo.</p>\r\n            <p class=\"pjustificado\">Jane también le cuenta dos sueños inquietantes en los que aparece un niño llorando (el mal augurio que ya conocíamos), simbolizando su propia vulnerabilidad. \r\n                Rochester, visiblemente nervioso pero tratando de mantener la calma, insiste en que todo fue una alucinación o que la responsable fue Grace Poole en un episodio de locura. \r\n                Le hace una promesa extraña: le explicará todo el misterio cuando lleven casados un año y un día. Esa noche, Jane busca consuelo durmiendo con Adèle, llorando ante la inminente pérdida\r\n                de su vida conocida.</p>'),
(26, 1, 26, 'Capítulo', '<p class=\"pjustificado\">El día de la boda comienza con una nota de presagio cuando Jane ve a dos extraños en el cementerio de la iglesia. En plena ceremonia, cuando el clérigo pregunta\r\n                si hay algún impedimento, uno de los extraños, el abogado Sr. Briggs, interviene: Rochester ya está casado. Revela que hace quince años, en Jamaica, Rochester contrajo matrimonio\r\n                con Bertha Mason, quien aún vive. El propio Richard Mason aparece para confirmar la historia.</p>\r\n            <p class=\"pjustificado\">Tras un estallido de furia, Rochester confiesa la verdad y lleva a todos a Thornfield para que vean por qué ocultó su secreto. En una habitación escondida tras\r\n                un tapiz en el tercer piso, encuentran a Bertha: una figura que Jane describe casi como un animal salvaje, con el cabello enmarañado, que gruñe y camina a cuatro patas. Es ella\r\n                quien intentó quemar a Rochester y quien atacó a Mason. Rochester explica que su locura lo obligó a esconderla bajo la vigilancia de Grace Poole.</p>\r\n            <p class=\"pjustificado\">Finalmente, Jane descubre que su tío, John Eyre, fue quien envió a Mason a detener la boda tras recibir la carta de Jane (la que escribió en el Capítulo 24).\r\n                Al quedarse sola, Jane se encierra en su habitación, despojándose de su traje de novia y sumergiéndose en una pena indescriptible, buscando en la oración la fuerza para sobrevivir\r\n                a la traición del hombre que ama.</p>'),
(27, 1, 27, 'Capítulo', '<p class=\"pjustificado\">Jane sale de su habitación y encuentra a Rochester esperándola. Aunque lo perdona internamente, se mantiene firme. Rochester la lleva a la biblioteca y\r\n                le hace una propuesta desesperada: huir juntos al sur de Francia para vivir como marido y mujer. Jane se niega rotundamente, pues sabe que, ante la ley y su propia conciencia, \r\n                nunca sería su esposa, sino su amante.</p>\r\n            <p class=\"pjustificado\">Para justificar su engaño, Rochester revela que su padre y su hermano lo enviaron a Jamaica para casarse con Bertha por su fortuna ($30,000$ libras), \r\n                ocultándole que la madre de ella estaba en un manicomio. Descubrió demasiado tarde que Bertha era violenta y grosera, rasgos que precedieron a su locura total. \r\n                Tras la muerte de su padre y hermano, regresó a Inglaterra y ocultó a Bertha en Thornfield para proteger su dignidad y la de ella, buscando consuelo en diversas amantes en Europa, \r\n                lo cual solo le trajo más vacío.</p>\r\n            <p class=\"pjustificado\">Jane siente una pena inmensa. Se siente tentada a quedarse con el único hombre que la ha amado. Sin embargo, su respeto propio y su moral vencen. \r\n                Tras un sueño profético donde su madre le ordena huir de la tentación, Jane toma su pequeña bolsa de dinero, sale sigilosamente de la casa y abandona Thornfield, \r\n                dejando atrás su corazón por salvar su alma.</p>'),
(28, 1, 28, 'Capítulo', '<p class=\"pjustificado\">Tras huir de Thornfield con apenas unas pocas monedas, Jane se ve obligada a gastar lo último que tiene en un carruaje \r\n                que la deja en un lugar remoto llamado Whitcross. Sin dinero, sin comida y sin techo, Jane vive la degradación absoluta de la pobreza: \r\n                duerme al raso entre los brezales, intenta cambiar su paño por un poco de pan y llega a mendigar sobras que un granjero iba a dar a sus cerdos.</p>\r\n            <p class=\"pjustificado\">En un estado de agotamiento extremo y bajo una lluvia torrencial, Jane sigue una luz en el páramo que la lleva hasta una casa\r\n                llamada Marsh End (o Moor House). A través de la ventana, observa a dos mujeres cultas, Diana y Mary, y a su criada Hannah. Cuando intenta pedir ayuda, \r\n                Hannah la rechaza confundiéndola con una vagabunda común. Justo cuando Jane se desploma aceptando su muerte, aparece St. John Rivers, el hermano de las\r\n                jóvenes y clérigo del lugar, quien la rescata citando la voluntad de Dios. Los tres hermanos la acogen, le dan alimento y calor, mientras Jane, para\r\n                proteger su pasado, les da un nombre falso: Jane Elliott.</p>'),
(29, 1, 29, 'Capítulo', '<p class=\"pjustificado\">Jane baja a la cocina y tiene un pequeño enfrentamiento con Hannah, la sirvienta, quien la juzga por su apariencia de mendiga. \r\n                Jane, con su característica dignidad, le da una lección de moral: le recuerda que la pobreza no es un crimen y que no debería juzgar a alguien solo por su \r\n                falta de dinero. Hannah, avergonzada, se disculpa y terminan haciendo las paces.</p>\r\n            <p class=\"pjustificado\">Cuando St. John le pide que cuente su historia, Jane (bajo el pseudónimo de Jane Elliott) les confiesa que es huérfana y que ha huido \r\n                de una situación dolorosa, pero se niega rotundamente a dar detalles sobre su pasado o el lugar de donde viene. St. John acepta su secreto y le promete \r\n                ayudarla a encontrar un trabajo que le permita ser independiente.</p>'),
(30, 1, 30, 'Capítulo', '<p class=\"pjustificado\">Jane entabla una amistad profunda con Diana y Mary. Las tres comparten el amor por la lectura y el estudio (especialmente de idiomas como el alemán). \r\n                Jane admira su independencia y su intelecto, sintiéndose por primera vez tratada como una igual en un entorno familiar sano. \r\n                Sin embargo, St. John sigue siendo un enigma: es un hombre entregado a su deber religioso, pero Jane nota que no es feliz; parece devorado por una ambición\r\n                severa y un deseo de hacer algo \"grande\" que lo aleja de la paz doméstica.</p>\r\n            <p class=\"pjustificado\">Los Rivers se enteran de que un tío suyo ha muerto y les ha dejado casi nada, legando su inmensa fortuna a otro pariente desconocido.\r\n                Esto entristece a las hermanas, no por el dinero en sí, sino porque esperaban que esa herencia les permitiera dejar de trabajar como institutrices en casas ajenas.</p>\r\n            <p class=\"pjustificado\">St. John finalmente le encuentra un trabajo a Jane. Le ofrece ser la maestra de una escuela para niñas pobres en el pueblo de Morton.\r\n                El salario es bajo y el trabajo humilde, pero Jane acepta con gratitud porque le ofrece lo que más desea: independencia total.</p>'),
(31, 1, 31, 'Capítulo', '<p class=\"pjustificado\">Jane inaugura su escuela con solo veinte alumnas, de las cuales solo tres saben leer. Al principio, se siente desanimada y lucha \r\n                contra una sensación de degradación; después de haber sido la compañera intelectual de Rochester, verse enseñando el abecedario en una aldea rural le\r\n                resulta un cambio brusco. Sin embargo, su autodisciplina vence de nuevo: se prohíbe a sí misma mirar atrás con nostalgia y se compromete a hacer su\r\n                trabajo con dignidad.</p>\r\n            <p class=\"pjustificado\">En este capítulo aparece un personaje clave: Rosamond Oliver, la hija del hombre más rico de la zona. Rosamond es \"la mujer más\r\n                hermosa que Jane ha visto jamás\" (incluso más que Blanche Ingram). Ella llega a la escuela y su presencia ilumina el lugar. Jane observa con atencián\r\n                la reacción de St. John Rivers ante ella, ya que es evidente que ambos se atraen pero St.John se obliga a ser distante con ella por su ambición\r\n                religiosa, que le impide casarse con alguien que solo busca placeres mundanos.</p>'),
(32, 1, 32, 'Capítulo', '<p class=\"pjustificado\">Jane gana el respeto y el cariño de sus alumnas en Morton, descubriendo que incluso las niñas más humildes tienen talentos ocultos. \r\n                Su vida es tranquila, pero sus noches están llenas de sueños vívidos y dolorosos con Rochester.</p>\r\n            <p class=\"pjustificado\">Rosamond Oliver visita la escuela con frecuencia, claramente buscando encontrarse con St. John. Un día, Jane se ofrece a hacerle un\r\n                retrato a lápiz a Rosamond. Mientras trabaja, St. John llega y queda cautivado por la imagen. Jane, valiente y directa, aprovecha la oportunidad para \r\n                confrontarlo. St. John explica que su verdadera vocación es ser misionero en la India. Sabe que Rosamond, con su amor por el lujo y la vida social, \r\n                moriría de aburrimiento y calor en un año. Prefiere sacrificar su felicidad personal por lo que considera su deber sagrado.</p>'),
(33, 1, 33, 'Capítulo', '<p class=\"pjustificado\">En una noche de tormenta de nieve, St. John Rivers llega a la cabaña de Jane. Tras un preámbulo lleno de tensión, le cuenta una \r\n                historia que parece salida de un libro: habla de una tal Jane Eyre, una institutriz que desapareció de Thornfield Hall tras un intento de boda ilegal\r\n                con el Sr. Rochester. St. John revela cómo la encontró: el trozo de papel que arrancó en el capítulo anterior tenía escrito el nombre real de ella; \r\n                el abogado de Londres, el Sr. Briggs (el mismo que detuvo la boda), ha estado buscándola desesperadamente porque su tío, John Eyre, ha muerto en \r\n                Madeira y le ha dejado a Jane toda su fortuna: 20,000 libras.</p>\r\n            <p class=\"pjustificado\">Lo más conmovedor para Jane no es el dinero. Al hacer preguntas sobre la familia de St. John, descubre la verdad definitiva:\r\n                el padre de St. John, Diana y Mary era el hermano de la madre de Jane. Los River son sus primos. En vez de regodearse en su riqueza, salta de alegría\r\n                al saber que tiene familia. Inmediatamente decide dividir las 20,000 libras en cuatro partes iguales ($5,000$ para cada uno), para que sus primos \r\n                también sean independientes y puedan dejar de trabajar como sirvientes o institutrices.</p>'),
(34, 1, 34, 'Capítulo', '<p class=\"pjustificado\">Tras repartir la herencia, las hermanas Diana y Mary regresan a Moor House, y por primera vez en su vida, Jane disfruta de un hogar \r\n                lleno de afecto y libertad económica. Sin embargo, St. John no se permite disfrutar. Se vuelve cada vez más exigente con Jane, pidiéndole que deje de \r\n                estudiar alemán y aprenda hindustani, preparándola para su misión en la India</p>\r\n            <p class=\"pjustificado\">Jane se siente anulada por la voluntad de hierro de su primo. Ella describe su influencia como una \"neblina helada\" que apaga su \r\n                chispa natural. El clímax del capítulo llega cuando St. John le hace una propuesta de matrimonio, pero de una forma totalmente desprovista de amor. \r\n                No le pide que sea su esposa por afecto, sino porque la considera una \"herramienta adecuada\" para su labor misionera.</p>\r\n            <p class=\"pjustificado\">Jane acepta ir a la India como su \"hermana\" o colaboradora, pero se niega a casarse con él. Ella sabe que un matrimonio sin amor \r\n                con un hombre tan frío serían una forma de suicidio emocional. Él se siente profundamente ofendido por su negativa, tachándola de rebelde ante la voluntad\r\n                de Dios, y comienza a tratarla con una cortesía gélida que hiere a Jane más que cualquier grito.</p>'),
(35, 1, 35, 'Capítulo', '<p class=\"pjustificado\">Tras el rechazo de Jane, St. John utiliza su arma más poderosa: la culpa religiosa. Durante una semana, la trata con una frialdad gélida \r\n                que hace que Jane se sienta como una pecadora ante Dios. Diana intenta advertirle que casarse con él sería una locura, pero St. John redobla su presión.</p>\r\n            <p class=\"pjustificado\">Una noche, St. John reza con tal fervor y autoridad que Jane se siente al borde de la rendición. Por un momento, cree que su destino\r\n                es sacrificarse y casarse con él para servir a la misión en la India. Está a punto de decir \"sí\", cuando de repente ocurre algo sobrenatural: \r\n                    en el silencio absoluto de la noche, Jane escucha una voz conocida que la llama, pero no es una voz que está en su cabeza, la está oyendo realmente. \r\n                    Reconoce al instante que es la voz de Edward Rochester.</p>\r\n            <p class=\"pjustificado\">Este fenómeno le devuelve la fuerza y la claridad. Rompe el hechizo de St. John, lo aparta y declara que ahora es ella quien tiene \r\n                un deber que cumplir.</p>'),
(36, 1, 36, 'Capítulo', '<p class=\"pjustificado\">Jane emprende un viaje de dos días en carruaje hacia el distrito de Millcote. Su impaciencia es tal que decide caminar \r\n                la última parte del trayecto. Al acercarse a Thornfield Hall, espera ver la imponente mansión de siempre, pero lo que encuentra es una visión desoladora:\r\n                un esqueleto ennegrecido y ruinoso. La casa ha sido consumida por el fuego.</p>\r\n            <p class=\"pjustificado\">Bertha Mason logró escapar de su encierro y prendió fuego a la habitación de Jane (el lugar de su mayor odio) y luego a toda la casa. \r\n                El dueño de la casa actuó con valentía, sacando a todos los criados y a Adèle del edificio en llamas. Rochester subió al tejado para intentar salvar a su \r\n                esposa, pero ella, entre gritos y risas dementes, se lanzó al vacío y murió en el acto.Al intentar bajar, una parte de la estructura colapsó sobre Rochester. \r\n                El resultado fue devastador: perdió la vista y le tuvieron que amputar una mano.</p>'),
(37, 1, 37, 'Capítulo', '<p class=\"pjustificado\">Jane se acerca a la casa y ve a Rochester salir a la puerta. Se queda impactada: su aspecto es descuidado, su mirada fija y sin brillo, y\r\n                se mueve con una tristeza errática. Parece un \"león enjaulado\". Jane entra en la casa, se encuentra con los antiguos criados (Mary y John) y toma una bandeja\r\n                con agua para llevársela ella misma.</p>\r\n            <p class=\"pjustificado\">Al principio, Rochester no cree que sea ella. Al ser ciego, la toca con manos temblorosas y piensa que es un espíritu o un sueño. \r\n                Jane le asegura que es ella, de carne y hueso, y le revela que ahora es una mujer rica e independiente. Esto es crucial: Jane ya no vuelve como una humilde institutriz, \r\n                sino como su igual (o incluso con más recursos que él en ese momento).</p>\r\n            <p class=\"pjustificado\">Rochester confiesa que, en un momento de desesperación absoluta, gritó el nombre de Jane al viento. Coinciden en que ambos escucharon la llamada\r\n                a la misma hora y el mismo día (el evento místico del Capítulo 35).</p>'),
(38, 1, 38, 'Capítulo', '<p class=\"pjustificado\">Jane y Rochester celebran una boda tranquila y privada. No hay grandes lujos ni invitados pretenciosos; su unión se basa ahora en una igualdad total. \r\n                Jane explica que ser su esposa es ser la parte más feliz de su propia existencia: ella es sus ojos (le describe el mundo) y él es su guía espiritual.</p>\r\n            <p class=\"pjustificado\">Jane saca a Adèle de la estricta escuela donde estaba y la lleva a una más amable cerca de casa. Adèle crece para convertirse en una joven dócil, \r\n                agradable y muy unida a Jane.</p>\r\n            <p class=\"pjustificado\">Diana y Mary Rivers se casan con hombres que las valoran y mantienen una relación estrecha y frecuente con su prima Jane.</p>\r\n            <p class=\"pjustificado\">St. John Rivers: Se marcha a la India como misionero. El libro termina con una nota sobre él: nunca se casó y, aunque está agotado y presiente su muerte cercana,\r\n                se siente realizado por haber cumplido lo que él considera su deber sagrado hacia Dios.</p>\r\n            <p class=\"pjustificado\">Tras dos años de matrimonio, Rochester recupera gradualmente la visión en un ojo. Esto le permite ver por primera vez a su hijo primogénito\r\n                (que heredó sus mismos ojos negros y brillantes). La novela cierra con una imagen de plenitud familiar, donde el sufrimiento pasado ha sido transformado en una paz profunda y merecida.</p>');

