--
-- Estructura de tabla para la tabla `symbols`
--

CREATE TABLE `symbols` (
  `id` int(11) NOT NULL,
  `simbolo_id` varchar(100) NOT NULL,
  `contenido` text NOT NULL,
  `work_id` int(11) NOT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Volcado de datos para la tabla `symbols`
--

INSERT INTO `symbols` (`id`, `simbolo_id`, `contenido`, `work_id`) VALUES
(1, '#fuegoHielo', 'El fuego y el hielo son usados por Brontë para representar una dicotomía en el amor. Mientras que el frío es la represión emocional, soledad, rigidez representada por John Rivers, el fuego es la pasión y el deseo de Rochester, sin embargo, es peligroso.\r\n        El fuego es el elemento que representa la relación que mantienen Jane y Rochester. Representa el calor y el hogar, pero como hemos dicho es peligroso debido a las emociones descontroladas. También es un elemento purificador.\r\nLo vemos presente en las conversaciones que mantienen frente a la chimenea, el el incendio final de Thornfield… \r\nEl hielo, por otro lado, es el elemento que domina las etapas en las que Jane sufre. El frío es la carencia de amor que Jane sufre en Lowood, a John Rivers se lo describe como un glaciar que busca apagar el fuego en su prima… El frío casi mata a Jane cuando huye de Thornfield y duerme a la intemperie: se despide del calor recibido por Rochester y ahora le toca enfrentarse a su ausencia.\r\nJane busca encontrar en este aspecto de su vida también el equilibrio, ya que sabe que mucho fuego conlleva a la locura y la destrucción, y mucho hielo lleva a la tiranía y a la muerte del alma. Ella es la única que logra equilibrar ambos.\r\n', 1),
(2, '#casa', 'Thornfield simboliza el secreto victoriano, la fachada es la respetabilidad, pero el interior es un tormento.\r\n        Los lugares a los que llega la luz, como el salón, la biblioteca o el comedor, son lugares en los que hay vida social, representando la vida pública de Rochester: un hombre rico y sofisticado. Jane intenta encajar aquí, sin embargo, no puede evitar sentirse como una extraña. \r\n        A medida que la oscuridad invade la casa, en el tercer piso y el ático, Jane puede sentir cosas extrañas. Aquí es donde se esconde el pasado reprimido de Rochester, su mujer Bertha. Podemos ver el ático como el subconsciente de la casa, ya que sabe lo que realmente está ocurriendo. Mientras todo parece tranquilo abajo, arriba se esconde la ira que acaba destruyendo toda la casa. Los ruidos, las risas y los incendios son \"fugas\" de ese secreto que no puede mantenerse encerrado para siempre.\r\n        Que Thornfield termine reducida a cenizas es un símbolo de purificación total.\r\n        Podemos comparar esta casa con las demás:\r\nGateshead: la cárcel de la infancia en la que se encuentra el lugar de castigo que inicia todo, el Cuarto Rojo.\r\nLowood: la institución fría y deshumanizada.\r\nMoor House: hogar en el que no hay secretos ni pasillos cerrados en el que la mente y la igualdad pueden florecer.\r\nFerndean: una casa modesta, rodeada de naturaleza, sin grandiosidades ni pretenciosidad, en la que el amor ya no se rige por estatus ni secretos.\r\n', 1),
(3, '#luzOscuridadBertha', 'En el apartado anterior hemos adelantado un poco el significado que se le da a este símbolo. La luz es un arma de doble filo, pues permite el descubrimiento, pero la realidad duele.\r\nLa oscuridad, aparte de ser los secretos, es el elemento que envuelve a Bertha Mason. Vive casi en una oscuridad total, que la deshumaniza y la borra de la existencia. Además, Bertha no es un simple personaje, es el doble oscuro de Jane, ya que representa los impulsos que ella intenta reprimir. una es luz, razón y autocontrol, mientras que la otra es oscuridad, locura, instinto.\r\nResulta irónico que Rochester acabe ciego, ya que tuvo que perder la vista física y sumirse en la oscuridad para ganar la visión moral y espiritual.\r\n', 1),
(4, '#cuartoRojo', 'Es la habitación en la que el tío Reed murió y dónde encierran a Jane de pequeña como castigo. Es un espacio de transición en el que la muchacha entra sumisa y aterrorizada y sale rebelde, consciente de su propia existencia al haberse visto reflejada en el espejo.\r\nTodos los elementos del cuarto tienen significado, incluso el color. El rojo está portadas partes (cortinas, paredes, alfombras…) y simboliza la ira reprimida de Jane. Sufre aquí su primer ataque de pánico que la marcará para siempre, cada vez que se siente atrapada o mal tratada su mente regresa a esta habitación.\r\nPodemos ver el Cuarto Rojo como un anticipo de lo que Bertha Mason sufre en el ático de Thornfield. Ambas son mujeres que han sido encerradas injustamente por haber sido consideradas una amenaza difícil de controlar.\r\n', 1),
(5, '#naturaleza', 'La Naturaleza es el único lugar en el que Jane puede ser realmente ella, libre. Se confiesa con ella y la usa como guía emocional, porque eso es también, un símbolo de sus sentimientos. El tiempo refleja lo que ella siente: cuando es castigada en Gateshead, el invierno es muy duro, cuando se enamora en Thornfield el verano llega y la naturaleza florece.\r\nCabe destacar el castaño partido entre los elementos naturales, ya que marca el ascenso y la caída de la esperanza de Jane. Rochester le pide matrimonio bajo el árbol, pero un rayo lo parte inmediatamente y esto es un presagio de lo que va a ocurrir. Al ser una unión impura, la Naturaleza busca advertir a Jane.\r\n', 1),
(6, '#pajaroEyre', 'Este símbolo define la esencia de Jane, se la describe como un pájaro ella misma lo utiliza para hablar de sí misma. A lo largo de la novela, evoluciona con ella, ya que comienzan como criaturas frágiles y heridas que acaban siendo capaces de cualquier cosa por su propia voluntad.\r\n        De pequeña, su vía de escape a los maltratos sufridos eran sus libros de aves, que a su vez representaban su deseo de volar lejos de allí.\r\n        Al principio, Rochester suele llamar a Jane pajarillo de forma cariñosa pero posesiva. Jane rechaza ser enjaulada en Thornfield, porque el amor no puede existir si uno tiene que sacrificar su libertad. \r\n        Por otro lado, el apellido de la protagonista no es casual. En inglés, Eyre se pronuncia exactamente igual que \"Air\" (aire), lo cual añade una capa simbólica profunda a su búsqueda de libertad. El aire representa la capacidad de Jane para desplazarse entre diferentes mundos (clases sociales, casas, estados mentales) sin perder su esencia\r\n', 1),
(7, '#madres', 'Como huérfana, Jane no tiene una raíz biológica, por lo que debe \"construirse\" a través de las mujeres que encuentra. De cada una coge lo que más le gusta para construir su identidad.\r\n\r\nSra. Reed: Injusticia y crueldad. Despierta su rebeldía y deseo de independencia.\r\nBessie Lee: Historias y folclore. Alimenta su imaginación y mundo interno.\r\nSrta. Temple: Educación y templanza. Le da las herramientas para ser una profesional digna.\r\nSra. Fairfax: Respeto y orden hogareño. Le ofrece la primera sensación de hogar estable.\r\nDiana y Mary: Igualdad e intelecto compartidos. Le dan el sentido de pertenencia y familia real.', 1);

